'use client';
import { useState, useRef } from "react";


const GUMIHO_IMG = "data:image/jpeg;base64,";

export default function GumihoButton() {
  const [show, setShow] = useState(false);
  const [pos, setPos] = useState({ x: 0, y: 0 });
  const btnRef = useRef<HTMLButtonElement>(null);

  const handleMouseEnter = (e: React.MouseEvent) => {
    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    setPos({ x: rect.left + rect.width / 2, y: rect.top });
    setShow(true);
  };

  return (
    <>
      <button
        ref={btnRef}
        onMouseEnter={handleMouseEnter}
        onMouseLeave={() => setShow(false)}
        className="text-[var(--accent)] font-semibold cursor-pointer bg-transparent border-none p-0 font-inherit text-inherit"
        style={{ fontFamily: "inherit", fontSize: "inherit" }}
      >
        Gumiho
      </button>

      {/* Floating photo popup — rendered via a fixed overlay so it escapes any overflow:hidden */}
      {show && (
        <div
          className="fixed z-[9999] pointer-events-none"
          style={{
            left: pos.x,
            top: pos.y,
            transform: "translate(-50%, calc(-100% - 14px))",
          }}
        >
          {/* Card */}
          <div
            style={{
              width: 120,
              borderRadius: 16,
              overflow: "hidden",
              border: "2px solid var(--accent, #2dd4bf)",
              boxShadow: "0 0 32px 4px #2dd4bf55, 0 8px 32px #0008",
              background: "#0a1a1a",
              animation: "gumihoFadeIn 0.22s cubic-bezier(.22,1,.36,1) both",
            }}
          >
            <img
              src={GUMIHO_IMG}
              alt="My Gumiho ♡"
              style={{ width: "100%", display: "block", objectFit: "cover" }}
            />
      
          </div>

          {/* Little tail */}
          <div
            style={{
              width: 0, height: 0,
              borderLeft: "8px solid transparent",
              borderRight: "8px solid transparent",
              borderTop: "8px solid var(--accent, #2dd4bf)",
              margin: "0 auto",
            }}
          />
        </div>
      )}

      {/* Keyframe — injected once */}
      <style>{"        @keyframes gumihoFadeIn {          from { opacity: 0; transform: translateY(10px) scale(0.94); }          to   { opacity: 1; transform: translateY(0)    scale(1); }        }      "}</style>
    </>
  );
}